// allowing a future prompt to trigger auto-approve again.
func TestUpdate_PermissionAutoApprove_ClearsGuardWhenPromptGone(t *testing.T) {
	m := newTestHomeWithCache(t)
	m.permissionStore.Remember(m.activeProject(), "/opt/*")

