	// Right on collapsed plan should expand
	n.Right()
	require.Len(t, n.rows, 2)
	assert.False(t, n.rows[0].Collapsed)
	assert.Equal(t, 0, n.selectedIdx) // still on header

	// Right on expanded plan should descend to first child
